1тЖТimport React, { useState, useEffect } from 'react';
2тЖТimport { Activity, FileText, Wrench, Shield, Users, Calendar, LogOut, UserPlus, Clock, Package } from 'lucide-react';
3тЖТ
4тЖТconst API = `${window.location.protocol}//${window.location.host}`;
5тЖТ
6тЖТconst Sidebar = ({ user, activeTab, onTabChange, onLogout }) => {
7тЖТ  const [restingToday, setRestingToday] = useState([]);
8тЖТ  const [currentTime, setCurrentTime] = useState(new Date());
9тЖТ
10тЖТ  useEffect(() => {
11тЖТ    const timer = setInterval(() => setCurrentTime(new Date()), 1000);
12тЖТ    return () => clearInterval(timer);
13тЖТ  }, []);
14тЖТ
15тЖТ  useEffect(() => {
16тЖТ    const fetchResting = async () => {
17тЖТ      try {
18тЖТ        const token = localStorage.getItem('token');
19тЖТ        const res = await fetch(`${API}/rest-days/today`, {
20тЖТ          headers: { Authorization: `Bearer ${token}` }
21тЖТ        });
22тЖТ        if (res.ok) {
23тЖТ          const data = await res.json();
24тЖТ          setRestingToday(data);
25тЖТ        }
26тЖТ      } catch (e) {}
27тЖТ    };
28тЖТ    fetchResting();
29тЖТ
30тЖТ    const h = () => fetchResting();
31тЖТ    window.addEventListener('app-refresh', h);
32тЖТ
33тЖТ  }, []);
34тЖТ
35тЖТ  const tabs = [
36тЖТ    { id: 'dashboard', label: 'Monitoring', icon: Activity, roles: ['ADMIN', 'MASTER', 'NAZORATCHI', 'OPERATOR'] },
37тЖТ    { id: 'master', label: 'Master Panel', icon: Wrench, roles: ['ADMIN', 'MASTER'] },
38тЖТ    { id: 'nazoratchi', label: 'Nazoratchi', icon: Shield, roles: ['ADMIN', 'NAZORATCHI'] },
39тЖТ    { id: 'users', label: 'Foydalanuvchilar', icon: Users, roles: ['ADMIN', 'NAZORATCHI'] },
40тЖТ    { id: 'reports', label: 'Hisobotlar', icon: FileText, roles: ['ADMIN', 'MASTER', 'NAZORATCHI'] },
41тЖТ    { id: 'mechanic', label: 'Mexanik', icon: Package, roles: ['ADMIN', 'MASTER', 'OPERATOR'] },
42тЖТ    { id: 'attendance', label: 'Davomat', icon: Calendar, roles: ['ADMIN', 'MASTER'] },
43тЖТ    { id: 'schedule', label: 'Jadval', icon: Clock, roles: ['ADMIN', 'MASTER', 'NAZORATCHI'] },
44тЖТ  ];
45тЖТ
46тЖТ  const filteredTabs = tabs.filter(t => t.roles.includes(user.role));
47тЖТ
48тЖТ  return (
49тЖТ    <div className="sidebar">
50тЖТ      <div className="sidebar-header">
51тЖТ        <h2>FazoLuxe</h2>
52тЖТ        <p className="sidebar-user">{user.full_name} ({user.role})</p>
53тЖТ      </div>
54тЖТ      <nav className="sidebar-nav">
55тЖТ        {filteredTabs.map(tab => (
56тЖТ          <button
57тЖТ            key={tab.id}
58тЖТ            className={`sidebar-tab ${activeTab === tab.id ? 'active' : ''}`}
59тЖТ            onClick={() => onTabChange(tab.id)}
60тЖТ          >
61тЖТ            <tab.icon size={18} />
62тЖТ            <span>{tab.label}</span>
63тЖТ          </button>
64тЖТ        ))}
65тЖТ      </nav>
66тЖТ      {restingToday.length > 0 && (
67тЖТ        <div className="sidebar-rest">
68тЖТ          <p className="rest-title">Bugun dam olish:</p>
69тЖТ          {restingToday.map(r => (
70тЖТ            <span key={r.operator_id} className="rest-name">{r.operator_name}</span>
71тЖТ          ))}
72тЖТ        </div>
73тЖТ      )}
74тЖТ      <div className="sidebar-footer">
75тЖТ        <div className="sidebar-time">
76тЖТ          {currentTime.toLocaleTimeString('uz-UZ')}
77тЖТ        </div>
78тЖТ        <button className="sidebar-logout" onClick={onLogout}>
79тЖТ          <LogOut size={16} />
80тЖТ          <span>Chiqish</span>
81тЖТ        </button>
82тЖТ      </div>
83тЖТ    </div>
84тЖТ  );
85тЖТ};
86тЖТ
87тЖТexport default Sidebar;
EOF

